```typescript
type RoverState = { x: number; y: number; heading: string };

const leftRotations: { [key: string]: string } = {
  N: "W",
  W: "S",
  S: "E",
  E: "N",
};

export function executeCommands(
  x: number,
  y: number,
  heading: string,
  commands: string
